final class EnrichAccessDeniedResponseWithRequestHint
{
    public function handle(Request $request, Closure $next): Response
    {
        $response = $next($request);

        if ($response->getStatusCode() !== 403) {
            return $response;
        }

        $body = json_decode($response->getContent(), associative: true);
        if (($body['code'] ?? null) !== 'access_denied') {
            return $response;
        }

        $resourceType = $this->resolveResourceType($request);
        $entry = $this->registry->find($resourceType);
        if ($entry === null) {
            return $response;
        }

        $body['code'] = 'access_denied.can_request';
        $body['resource'] = ['type' => $resourceType, 'id' => $request->route('id')];
        $body['permissions_wanted'] = $entry->permissions;
        $body['request_url'] = route('tenant.access-requests.store');
        $body['request_payload_template'] = [
            'resource_type' => $resourceType,
            'resource_id' => $request->route('id'),
            'permissions_wanted' => $entry->permissions,
            'reason' => '',
        ];

        $this->metrics->increment('access_requests.request_hint_offered.total', labels: [
            'application_id' => $request->attributes->get('application_id'),
            'tenant_id' => $request->attributes->get('tenant_id'),
            'resource_type' => $resourceType,
        ]);

        return $response->setContent(json_encode($body));
    }
}
